import "./styles/Books.css";

const books = [
  { id: 1, title: "Clean Code", author: "Robert C Martin" },
  { id: 2, title: "Harry Potter", author: "J K Rowling" },
  { id: 3, title: "The Hobbit", author: "J R R Tolkien" },
  { id: 4, title: "Atomic Habits", author: "James Clear" },
  { id: 5, title: "Rich Dad Poor Dad", author: "Robert Kiyosaki" },
  { id: 6, title: "Sapiens", author: "Yuval Noah Harari" },
  { id: 7, title: "Think and Grow Rich", author: "Napoleon Hill" },
  { id: 8, title: "The Alchemist", author: "Paulo Coelho" },
];

function Books() {
  return (
    <div className="books-page">
      <h1 className="books-title">The Library</h1>

      <div className="books-grid">
        {books.map(book => (
          <div className="book-card" key={book.id}>
            <h3>{book.title}</h3>
            <p>{book.author}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Books;
